  "sentences": [
    {
      "text": "我以前去過臺北的故宮。",
      "pinyin": "Wǒ yǐqián qù guò Táiběi de Gùgōng.",
      "pinyin_numeric": "wo3 yi3qian2 qu4 guo4 Tai2bei3 de Gu4gong1.",
      "translation_en": "I have been to the National Palace Museum in Taipei before.",
      "translation_ko": "저는 예전에 타이베이의 고궁박물원에 가 본 적이 있습니다."
    },
    {
      "text": "我以前吃過臺南的牛肉麵。",
      "pinyin": "Wǒ yǐqián chī guò Táinán de niúròu miàn.",
      "pinyin_numeric": "wo3 yi3qian2 chi1 guo4 Tai2nan2 de niu2rou4 mian4.",
      "translation_en": "I have eaten beef noodles in Tainan before.",
      "translation_ko": "저는 예전에 타이난의 소고기 국수를 먹어 본 적이 있습니다."
    },
    {
      "text": "我以前喝過珍珠奶茶。",
      "pinyin": "Wǒ yǐqián hē guò zhēnzhū nǎichá.",
      "pinyin_numeric": "wo3 yi3qian2 he1 guo4 zhen1zhu1 nai3cha2.",
      "translation_en": "I have had bubble tea before.",
      "translation_ko": "저는 예전에 버블티를 마셔 본 적이 있습니다."
    },
    {
      "text": "我以前看過淡水的風景。",
      "pinyin": "Wǒ yǐqián kàn guò Dànshuǐ de fēngjǐng.",
      "pinyin_numeric": "wo3 yi3qian2 kan4 guo4 Dan4shui3 de feng1jing3.",
      "translation_en": "I have seen the scenery of Tamsui before.",
      "translation_ko": "저는 예전에 단수이의 풍경을 본 적이 있습니다."
    },
    {
      "text": "我以前聽過這首歌。",
      "pinyin": "Wǒ yǐqián tīng guò zhè shǒu gē.",
      "pinyin_numeric": "wo3 yi3qian2 ting1 guo4 zhe4 shou3 ge1.",
      "translation_en": "I have heard this song before.",
      "translation_ko": "저는 예전에 이 노래를 들어 본 적이 있습니다."
    },
    {
      "text": "我以前學過中文。",
      "pinyin": "Wǒ yǐqián xué guò Zhōngwén.",
      "pinyin_numeric": "wo3 yi3qian2 xue2 guo4 Zhong1wen2.",
      "translation_en": "I have studied Chinese before.",
      "translation_ko": "저는 예전에 중국어를 배워 본 적이 있습니다."
    },
    {
      "text": "我以前做過這個工作。",
      "pinyin": "Wǒ yǐqián zuò guò zhège gōngzuò.",
      "pinyin_numeric": "wo3 yi3qian2 zuo4 guo4 zhe4ge gong1zuo4.",
      "translation_en": "I have done this job before.",
      "translation_ko": "저는 예전에 이 일을 해 본 적이 있습니다."
    },
    {
      "text": "我從來沒有去過國外。",
      "pinyin": "Wǒ cónglái méiyǒu qù guò guówài.",
      "pinyin_numeric": "wo3 cong2lai2 mei2you3 qu4 guo4 guo2wai4.",
      "translation_en": "I have never been abroad.",
      "translation_ko": "저는 한 번도 해외에 가 본 적이 없습니다."
    },
    {
      "text": "這是我第一次去花蓮。",
      "pinyin": "Zhè shì wǒ dì yī cì qù Huālián.",
      "pinyin_numeric": "zhe4 shi4 wo3 di4 yi1 ci4 qu4 Hua1lian2.",
      "translation_en": "This is my first time going to Hualien.",
      "translation_ko": "이번이 제가 처음으로 화롄에 가는 것입니다."
    },
    {
      "text": "我以前去過好幾次夜市。",
      "pinyin": "Wǒ yǐqián qù guò hǎo jǐ cì yèshì.",
      "pinyin_numeric": "wo3 yi3qian2 qu4 guo4 hao3 ji3 ci4 ye4shi4.",
      "translation_en": "I have been to the night market several times before.",
      "translation_ko": "저는 예전에 야시장에 여러 번 가 본 적이 있습니다."
    }
  ]
}
